-- Roles por defecto del tenant J Burguer y su mapeo de permisos.
-- Fuente de verdad del mapeo: @jburger/domain-roles (defaultRolePermissionMap).
-- Estándar de identificadores: RFC 4122, formato v4 (ver ADR-022).
insert into public.roles (id, tenant_id, nombre, descripcion) values
  ('e0000000-0000-4000-8000-000000000001', 'a0000000-0000-4000-8000-000000000001', 'OWNER', 'Propietario del negocio'),
  ('e0000000-0000-4000-8000-000000000002', 'a0000000-0000-4000-8000-000000000001', 'ADMIN', 'Administración general'),
  ('e0000000-0000-4000-8000-000000000003', 'a0000000-0000-4000-8000-000000000001', 'MANAGER', 'Encargado de sucursal'),
  ('e0000000-0000-4000-8000-000000000004', 'a0000000-0000-4000-8000-000000000001', 'CAJERO', 'Caja y cobros'),
  ('e0000000-0000-4000-8000-000000000005', 'a0000000-0000-4000-8000-000000000001', 'COCINA', 'Cocina'),
  ('e0000000-0000-4000-8000-000000000006', 'a0000000-0000-4000-8000-000000000001', 'DELIVERY', 'Reparto'),
  ('e0000000-0000-4000-8000-000000000007', 'a0000000-0000-4000-8000-000000000001', 'SOPORTE', 'Soporte'),
  ('e0000000-0000-4000-8000-000000000008', 'a0000000-0000-4000-8000-000000000001', 'CLIENTE', 'Cliente final')
on conflict (id) do nothing;

with role_permission_map (role_id, permission_key) as (
  values
    ('e0000000-0000-4000-8000-000000000001'::uuid, 'users.read'), ('e0000000-0000-4000-8000-000000000001', 'users.write'), ('e0000000-0000-4000-8000-000000000001', 'roles.read'), ('e0000000-0000-4000-8000-000000000001', 'roles.write'), ('e0000000-0000-4000-8000-000000000001', 'permissions.read'), ('e0000000-0000-4000-8000-000000000001', 'permissions.write'), ('e0000000-0000-4000-8000-000000000001', 'audit.read'), ('e0000000-0000-4000-8000-000000000001', 'audit.export'), ('e0000000-0000-4000-8000-000000000001', 'tenants.assign'), ('e0000000-0000-4000-8000-000000000001', 'branches.assign'), ('e0000000-0000-4000-8000-000000000001', 'products.read'), ('e0000000-0000-4000-8000-000000000001', 'products.write'), ('e0000000-0000-4000-8000-000000000001', 'sessions.read'), ('e0000000-0000-4000-8000-000000000001', 'sessions.revoke'),
    ('e0000000-0000-4000-8000-000000000002', 'users.read'), ('e0000000-0000-4000-8000-000000000002', 'users.write'), ('e0000000-0000-4000-8000-000000000002', 'roles.read'), ('e0000000-0000-4000-8000-000000000002', 'roles.write'), ('e0000000-0000-4000-8000-000000000002', 'permissions.read'), ('e0000000-0000-4000-8000-000000000002', 'audit.read'), ('e0000000-0000-4000-8000-000000000002', 'branches.assign'), ('e0000000-0000-4000-8000-000000000002', 'products.read'), ('e0000000-0000-4000-8000-000000000002', 'products.write'), ('e0000000-0000-4000-8000-000000000002', 'sessions.read'), ('e0000000-0000-4000-8000-000000000002', 'sessions.revoke'),
    ('e0000000-0000-4000-8000-000000000003', 'users.read'), ('e0000000-0000-4000-8000-000000000003', 'products.read'), ('e0000000-0000-4000-8000-000000000003', 'products.write'), ('e0000000-0000-4000-8000-000000000003', 'orders.read'), ('e0000000-0000-4000-8000-000000000003', 'orders.write'), ('e0000000-0000-4000-8000-000000000003', 'branches.assign'),
    ('e0000000-0000-4000-8000-000000000004', 'orders.read'), ('e0000000-0000-4000-8000-000000000004', 'orders.write'), ('e0000000-0000-4000-8000-000000000004', 'payments.read'),
    ('e0000000-0000-4000-8000-000000000005', 'orders.read'), ('e0000000-0000-4000-8000-000000000005', 'orders.write'),
    ('e0000000-0000-4000-8000-000000000006', 'orders.read'),
    ('e0000000-0000-4000-8000-000000000007', 'support.access'), ('e0000000-0000-4000-8000-000000000007', 'users.read'), ('e0000000-0000-4000-8000-000000000007', 'orders.read'),
    ('e0000000-0000-4000-8000-000000000008', 'products.read'), ('e0000000-0000-4000-8000-000000000008', 'orders.read')
)
insert into public.role_permissions (role_id, permission_id, tenant_id)
select map.role_id, p.id, 'a0000000-0000-4000-8000-000000000001'
from role_permission_map map
join public.permissions p on p.key = map.permission_key
on conflict (role_id, permission_id) do nothing;
